SELECT DISTINCT date, CAST(EXTRACT(year FROM date) AS INTEGER) AS year, CAST(EXTRACT(month FROM date) AS INTEGER) AS month, agente_regulado, codigo_do_produto, nome_do_produto, regiao_de_origem, uf_origem, regiao_de_destino, uf_destino, mercado_destinatario, quantidade_de_produto_mil_m3 FROM (SELECT make_date(TRY_CAST(trim("ano") AS INTEGER), CASE upper(trim("mes")) WHEN 'JAN' THEN 1 WHEN 'JANEIRO' THEN 1 WHEN 'FEV' THEN 2 WHEN 'FEVEREIRO' THEN 2 WHEN 'MAR' THEN 3 WHEN 'MARÇO' THEN 3 WHEN 'MARCO' THEN 3 WHEN 'ABR' THEN 4 WHEN 'ABRIL' THEN 4 WHEN 'MAI' THEN 5 WHEN 'MAIO' THEN 5 WHEN 'JUN' THEN 6 WHEN 'JUNHO' THEN 6 WHEN 'JUL' THEN 7 WHEN 'JULHO' THEN 7 WHEN 'AGO' THEN 8 WHEN 'AGOSTO' THEN 8 WHEN 'SET' THEN 9 WHEN 'SETEMBRO' THEN 9 WHEN 'OUT' THEN 10 WHEN 'OUTUBRO' THEN 10 WHEN 'NOV' THEN 11 WHEN 'NOVEMBRO' THEN 11 WHEN 'DEZ' THEN 12 WHEN 'DEZEMBRO' THEN 12 ELSE TRY_CAST(trim("mes") AS INTEGER) END, 1) AS date, NULLIF(TRIM("agente_regulado"), '') AS agente_regulado, NULLIF(TRIM("codigo_do_produto"), '') AS codigo_do_produto, NULLIF(TRIM("nome_do_produto"), '') AS nome_do_produto, NULLIF(TRIM("regiao_de_origem"), '') AS regiao_de_origem, NULLIF(TRIM("uf_origem"), '') AS uf_origem, NULLIF(TRIM("regiao_de_destino"), '') AS regiao_de_destino, NULLIF(TRIM("uf_destino"), '') AS uf_destino, NULLIF(TRIM("mercado_destinatario"), '') AS mercado_destinatario, TRY_CAST(replace(replace(trim("quantidade_de_produto_mil_m3"), '.', ''), ',', '.') AS DOUBLE) AS quantidade_de_produto_mil_m3 FROM "anp-brazil-mdpg-trr") WHERE date IS NOT NULL AND (quantidade_de_produto_mil_m3 IS NOT NULL)
